  1→import React, { useState, useMemo, useCallback } from 'react';
  2→import { Target, Plus, Sparkles, Trash2, ToggleRight, ToggleLeft, Search, Tag } from 'lucide-react';
  3→import type { User } from '../../types';
  4→import type { TrackedQuery, QueryType } from '../../types/v3-types';
  5→import { getTrackedQueries, saveTrackedQueries, getProjectConfig, saveProjectConfig } from '../../services/v3/citation-storage';
  6→import { generateTrackedQueries } from '../../services/v3/query-generator';
  7→
  8→interface Props {
  9→  onBack: () => void;
 10→  user: User | null;
 11→  onNavigate: (view: string) => void;
 12→}
 13→
 14→const QUERY_TYPE_META: Record<QueryType, { label: string; color: string; bg: string }> = {
 15→  informational: { label: 'Informationnelle', color: 'text-blue-400', bg: 'bg-blue-500/10 border-blue-500/20' },
 16→  comparative: { label: 'Comparative', color: 'text-orange-400', bg: 'bg-orange-500/10 border-orange-500/20' },
 17→  transactional: { label: 'Transactionnelle', color: 'text-green-400', bg: 'bg-green-500/10 border-green-500/20' },
 18→  reputation: { label: 'Réputation', color: 'text-pink-400', bg: 'bg-pink-500/10 border-pink-500/20' },
 19→};
 20→
 21→const TrackedQueriesPage: React.FC<Props> = ({ onBack, user }) => {
 22→  const projectId = user?.id || 'default';
 23→  const [queries, setQueries] = useState<TrackedQuery[]>(() => getTrackedQueries(projectId));
 24→  const [isGenerating, setIsGenerating] = useState(false);
 25→  const [newQueryText, setNewQueryText] = useState('');
 26→  const [newQueryType, setNewQueryType] = useState<QueryType>('informational');
 27→  const [showAddForm, setShowAddForm] = useState(false);
 28→  const [filterType, setFilterType] = useState<QueryType | 'all'>('all');
 29→
 30→  // Setup form state
 31→  const config = useMemo(() => getProjectConfig(projectId), [projectId]);
 32→  const [setupNiche, setSetupNiche] = useState(config?.niche || '');
 33→  const [setupCountry, setSetupCountry] = useState(config?.country || 'Belgique');
 34→  const [setupBrand, setSetupBrand] = useState(config?.clientBrand || '');
 35→  const [setupUrl, setSetupUrl] = useState(config?.clientUrl || '');
 36→  const needsSetup = !config;
 37→
 38→  const filteredQueries = useMemo(() => {
 39→    if (filterType === 'all') return queries;
 40→    return queries.filter(q => q.queryType === filterType);
 41→  }, [queries, filterType]);
 42→
 43→  const persistQueries = useCallback((updated: TrackedQuery[]) => {
 44→    setQueries(updated);
 45→    saveTrackedQueries(projectId, updated);
 46→  }, [projectId]);
 47→
 48→  const handleSaveSetup = () => {
 49→    if (!setupNiche || !setupBrand || !setupUrl) return;
 50→    saveProjectConfig({
 51→      projectId,
 52→      clientUrl: setupUrl,
 53→      clientBrand: setupBrand,
 54→      brandVariants: [setupBrand],
 55→      productKeywords: [],
 56→      niche: setupNiche,
 57→      country: setupCountry,
 58→    });
 59→    // Force re-render
 60→    window.location.reload();
 61→  };
 62→
 63→  const handleGenerateSuggestions = async () => {
 64→    const cfg = getProjectConfig(projectId);
 65→    if (!cfg) return;
 66→    setIsGenerating(true);
 67→    try {
 68→      const suggestions = await generateTrackedQueries(cfg.niche, cfg.country, cfg.clientBrand);
 69→      const newQueries: TrackedQuery[] = suggestions.map(s => ({
 70→        id: crypto.randomUUID(),
 71→        projectId,
 72→        queryText: s.text,
 73→        queryType: s.type,
 74→        variations: s.variations,
 75→        isActive: true,
 76→        isSuggested: true,
 77→        createdAt: new Date().toISOString(),
 78→      }));
 79→      persistQueries([...queries, ...newQueries]);
 80→    } catch (error) {
 81→      console.error('Erreur génération:', error);
 82→    } finally {
 83→      setIsGenerating(false);
 84→    }
 85→  };
 86→
 87→  const handleAddQuery = () => {
 88→    if (!newQueryText.trim()) return;
 89→    const newQuery: TrackedQuery = {
 90→      id: crypto.randomUUID(),
 91→      projectId,
 92→      queryText: newQueryText.trim(),
 93→      queryType: newQueryType,
 94→      variations: [newQueryText.trim()],
 95→      isActive: true,
 96→      isSuggested: false,
 97→      createdAt: new Date().toISOString(),
 98→    };
 99→    persistQueries([...queries, newQuery]);
100→    setNewQueryText('');
101→    setShowAddForm(false);
102→  };
103→
104→  const handleToggle = (id: string) => {
105→    const updated = queries.map(q =>
106→      q.id === id ? { ...q, isActive: !q.isActive } : q
107→    );
108→    persistQueries(updated);
109→  };
110→
111→  const handleDelete = (id: string) => {
112→    persistQueries(queries.filter(q => q.id !== id));
113→  };
114→
115→  // Setup form
116→  if (needsSetup) {
117→    return (
118→      <div className="animate-in fade-in duration-500">
119→        <div className="max-w-xl mx-auto">
120→          <div className="mb-8 text-center">
121→            <div className="w-16 h-16 rounded-2xl bg-cyan-500/20 flex items-center justify-center border border-cyan-500/30 mx-auto mb-4">
122→              <Target size={32} className="text-cyan-400" />
123→            </div>
124→            <h1 className="text-2xl font-bold text-white mb-2">Configuration du projet</h1>
125→            <p className="text-gray-500">Configurez votre marque pour commencer le suivi des citations IA.</p>
126→          </div>
127→
128→          <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] space-y-4">
129→            <div>
130→              <label className="text-xs text-gray-500 uppercase tracking-wider font-medium mb-1.5 block">Nom de marque</label>
131→              <input value={setupBrand} onChange={e => setSetupBrand(e.target.value)} placeholder="Ex: MediaMarkt" className="w-full px-4 py-3 bg-white/[0.04] border border-white/[0.08] rounded-xl text-white placeholder:text-gray-600 focus:border-cyan-500/50 focus:outline-none transition-colors" />
132→            </div>
133→            <div>
134→              <label className="text-xs text-gray-500 uppercase tracking-wider font-medium mb-1.5 block">URL du site</label>
135→              <input value={setupUrl} onChange={e => setSetupUrl(e.target.value)} placeholder="Ex: mediamarkt.be" className="w-full px-4 py-3 bg-white/[0.04] border border-white/[0.08] rounded-xl text-white placeholder:text-gray-600 focus:border-cyan-500/50 focus:outline-none transition-colors" />
136→            </div>
137→            <div>
138→              <label className="text-xs text-gray-500 uppercase tracking-wider font-medium mb-1.5 block">Niche / secteur</label>
139→              <input value={setupNiche} onChange={e => setSetupNiche(e.target.value)} placeholder="Ex: électronique grand public" className="w-full px-4 py-3 bg-white/[0.04] border border-white/[0.08] rounded-xl text-white placeholder:text-gray-600 focus:border-cyan-500/50 focus:outline-none transition-colors" />
140→            </div>
141→            <div>
142→              <label className="text-xs text-gray-500 uppercase tracking-wider font-medium mb-1.5 block">Pays</label>
143→              <input value={setupCountry} onChange={e => setSetupCountry(e.target.value)} placeholder="Ex: Belgique" className="w-full px-4 py-3 bg-white/[0.04] border border-white/[0.08] rounded-xl text-white placeholder:text-gray-600 focus:border-cyan-500/50 focus:outline-none transition-colors" />
144→            </div>
145→            <button onClick={handleSaveSetup} disabled={!setupBrand || !setupUrl || !setupNiche} className="w-full py-3 bg-gradient-to-r from-cyan-500 to-blue-600 text-white font-bold rounded-xl hover:from-cyan-600 hover:to-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed">
146→              Sauvegarder et continuer
147→            </button>
148→          </div>
149→        </div>
150→      </div>
151→    );
152→  }
153→
154→  return (
155→    <div className="animate-in fade-in duration-500 pb-24">
156→      {/* Header */}
157→      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
158→        <div>
159→          <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
160→            <div className="w-10 h-10 rounded-2xl bg-purple-500/20 flex items-center justify-center border border-purple-500/30">
161→              <Target size={24} className="text-purple-400" />
162→            </div>
163→            Requêtes cibles
164→          </h1>
165→          <p className="text-gray-500">{queries.length} requêtes configurées &bull; {queries.filter(q => q.isActive).length} actives</p>
166→        </div>
167→        <div className="flex gap-3">
168→          <button onClick={handleGenerateSuggestions} disabled={isGenerating} className="px-4 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors text-sm flex items-center gap-2 disabled:opacity-50">
169→            <Sparkles size={16} className={isGenerating ? 'animate-spin' : ''} />
170→            {isGenerating ? 'Génération...' : 'Générer des suggestions IA'}
171→          </button>
172→          <button onClick={() => setShowAddForm(!showAddForm)} className="px-4 py-2.5 bg-white/[0.06] border border-white/[0.1] text-white font-bold rounded-2xl hover:bg-white/[0.1] transition-colors text-sm flex items-center gap-2">
173→            <Plus size={16} /> Ajouter
174→          </button>
175→        </div>
176→      </div>
177→
178→      {/* Add form */}
179→      {showAddForm && (
180→        <div className="ninja-card p-5 rounded-2xl border border-purple-500/20 mb-6 animate-in slide-in-from-top-2">
181→          <div className="flex flex-col sm:flex-row gap-3">
182→            <input value={newQueryText} onChange={e => setNewQueryText(e.target.value)} placeholder="Ex: meilleur smartphone 2026" className="flex-1 px-4 py-3 bg-white/[0.04] border border-white/[0.08] rounded-xl text-white placeholder:text-gray-600 focus:border-purple-500/50 focus:outline-none" onKeyDown={e => e.key === 'Enter' && handleAddQuery()} />
183→            <select value={newQueryType} onChange={e => setNewQueryType(e.target.value as QueryType)} className="px-4 py-3 bg-white/[0.04] border border-white/[0.08] rounded-xl text-white focus:border-purple-500/50 focus:outline-none appearance-none cursor-pointer">
184→              <option value="informational">Informationnelle</option>
185→              <option value="comparative">Comparative</option>
186→              <option value="transactional">Transactionnelle</option>
187→              <option value="reputation">Réputation</option>
188→            </select>
189→            <button onClick={handleAddQuery} disabled={!newQueryText.trim()} className="px-6 py-3 bg-purple-500 text-white font-bold rounded-xl hover:bg-purple-600 transition-colors disabled:opacity-50">
190→              Ajouter
191→            </button>
192→          </div>
193→        </div>
194→      )}
195→
196→      {/* Filters */}
197→      <div className="flex gap-2 mb-6 overflow-x-auto pb-2">
198→        {(['all', 'informational', 'comparative', 'transactional', 'reputation'] as const).map(type => (
199→          <button key={type} onClick={() => setFilterType(type)} className={`px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors border ${
200→            filterType === type ? 'bg-purple-500/20 text-purple-300 border-purple-500/30' : 'bg-white/[0.04] text-gray-500 border-white/[0.06] hover:text-white'
201→          }`}>
202→            {type === 'all' ? `Toutes (${queries.length})` : `${QUERY_TYPE_META[type].label} (${queries.filter(q => q.queryType === type).length})`}
203→          </button>
204→        ))}
205→      </div>
206→
207→      {/* Query list */}
208→      <div className="space-y-3">
209→        {filteredQueries.map(query => {
210→          const typeMeta = QUERY_TYPE_META[query.queryType];
211→          return (
212→            <div key={query.id} className={`ninja-card p-5 rounded-2xl border transition-all ${query.isActive ? 'border-white/[0.08]' : 'border-white/[0.04] opacity-50'}`}>
213→              <div className="flex items-start justify-between gap-3">
214→                <div className="flex-1 min-w-0">
215→                  <div className="flex items-center gap-2 mb-2">
216→                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider border ${typeMeta.bg} ${typeMeta.color}`}>
217→                      {typeMeta.label}
218→                    </span>
219→                    {query.isSuggested && (
220→                      <span className="text-[10px] px-2 py-0.5 rounded-full bg-purple-500/10 text-purple-400 border border-purple-500/20">
221→                        IA
222→                      </span>
223→                    )}
224→                  </div>
225→                  <p className="text-sm font-medium text-white mb-2">{query.queryText}</p>
226→                  <div className="flex flex-wrap gap-1.5">
227→                    {query.variations.map((v, i) => (
228→                      <span key={i} className="text-[10px] px-2 py-1 bg-white/[0.04] border border-white/[0.06] rounded text-gray-500 truncate max-w-[200px]">
229→                        {v}
230→                      </span>
231→                    ))}
232→                  </div>
233→                </div>
234→                <div className="flex items-center gap-2 shrink-0">
235→                  <button onClick={() => handleToggle(query.id)} className="text-gray-500 hover:text-white transition-colors" title={query.isActive ? 'Désactiver' : 'Activer'}>
236→                    {query.isActive ? <ToggleRight size={22} className="text-purple-400" /> : <ToggleLeft size={22} />}
237→                  </button>
238→                  <button onClick={() => handleDelete(query.id)} className="text-gray-600 hover:text-red-400 transition-colors" title="Supprimer">
239→                    <Trash2 size={16} />
240→                  </button>
241→                </div>
242→              </div>
243→            </div>
244→          );
245→        })}
246→
247→        {filteredQueries.length === 0 && (
248→          <div className="ninja-card p-12 rounded-2xl border border-dashed border-white/[0.08] text-center">
249→            <Search size={32} className="text-gray-600 mx-auto mb-3" />
250→            <p className="text-sm text-gray-500">Aucune requête configurée.</p>
251→            <p className="text-xs text-gray-600 mt-1">Ajoutez des requêtes manuellement ou générez des suggestions IA.</p>
252→          </div>
253→        )}
254→      </div>
255→    </div>
256→  );
257→};
258→
259→export default TrackedQueriesPage;
