  1→import React, { useState, useMemo } from 'react';
  2→import { FileSearch, ChevronDown, ChevronUp, ExternalLink } from 'lucide-react';
  3→import type { User } from '../../types';
  4→import type { CitationCheck, AIEngineId } from '../../types/v3-types';
  5→import { getCitationChecks, getTrackedQueries } from '../../services/v3/citation-storage';
  6→
  7→interface Props {
  8→  onBack: () => void;
  9→  user: User | null;
 10→  onNavigate: (view: string) => void;
 11→}
 12→
 13→const ENGINE_META: Record<AIEngineId, { name: string; icon: string; color: string }> = {
 14→  chatgpt: { name: 'ChatGPT', icon: '🟢', color: '#10a37f' },
 15→  perplexity: { name: 'Perplexity', icon: '🔵', color: '#20b8cd' },
 16→  gemini: { name: 'Gemini', icon: '🟣', color: '#8b5cf6' },
 17→};
 18→
 19→const CitationDetailPage: React.FC<Props> = ({ onBack, user }) => {
 20→  const projectId = user?.id || 'default';
 21→  const checks = useMemo(() => getCitationChecks(projectId), [projectId]);
 22→  const queries = useMemo(() => getTrackedQueries(projectId), [projectId]);
 23→  const [expandedCheckId, setExpandedCheckId] = useState<string | null>(null);
 24→  const [filterEngine, setFilterEngine] = useState<AIEngineId | 'all'>('all');
 25→  const [filterQuery, setFilterQuery] = useState<string>('all');
 26→
 27→  const filteredChecks = useMemo(() => {
 28→    let result = [...checks].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
 29→    if (filterEngine !== 'all') result = result.filter(c => c.engine === filterEngine);
 30→    if (filterQuery !== 'all') result = result.filter(c => c.trackedQueryId === filterQuery);
 31→    return result;
 32→  }, [checks, filterEngine, filterQuery]);
 33→
 34→  const getScoreBadge = (score: number) => {
 35→    if (score >= 70) return 'bg-green-500/20 text-green-400';
 36→    if (score >= 40) return 'bg-yellow-500/20 text-yellow-400';
 37→    return 'bg-red-500/20 text-red-400';
 38→  };
 39→
 40→  return (
 41→    <div className="animate-in fade-in duration-500 pb-24">
 42→      <div className="mb-8">
 43→        <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
 44→          <div className="w-10 h-10 rounded-2xl bg-blue-500/20 flex items-center justify-center border border-blue-500/30">
 45→            <FileSearch size={24} className="text-blue-400" />
 46→          </div>
 47→          Détail des vérifications
 48→        </h1>
 49→        <p className="text-gray-500">{checks.length} vérification{checks.length > 1 ? 's' : ''} enregistrée{checks.length > 1 ? 's' : ''}</p>
 50→      </div>
 51→
 52→      {/* Filters */}
 53→      <div className="flex flex-wrap gap-3 mb-6">
 54→        <select value={filterEngine} onChange={e => setFilterEngine(e.target.value as AIEngineId | 'all')} className="px-4 py-2 bg-white/[0.04] border border-white/[0.08] rounded-xl text-sm text-white focus:border-blue-500/50 focus:outline-none appearance-none cursor-pointer">
 55→          <option value="all">Tous les moteurs</option>
 56→          <option value="chatgpt">ChatGPT</option>
 57→          <option value="perplexity">Perplexity</option>
 58→          <option value="gemini">Gemini</option>
 59→        </select>
 60→        <select value={filterQuery} onChange={e => setFilterQuery(e.target.value)} className="px-4 py-2 bg-white/[0.04] border border-white/[0.08] rounded-xl text-sm text-white focus:border-blue-500/50 focus:outline-none appearance-none cursor-pointer max-w-[300px]">
 61→          <option value="all">Toutes les requêtes</option>
 62→          {queries.map(q => (
 63→            <option key={q.id} value={q.id}>{q.queryText}</option>
 64→          ))}
 65→        </select>
 66→      </div>
 67→
 68→      {/* Results */}
 69→      <div className="space-y-3">
 70→        {filteredChecks.map(check => {
 71→          const meta = ENGINE_META[check.engine];
 72→          const isExpanded = expandedCheckId === check.id;
 73→          const isCited = check.detection.urlExactMatch || check.detection.brandExactMatch || check.detection.urlInSource;
 74→
 75→          return (
 76→            <div key={check.id} className="ninja-card rounded-2xl border border-white/[0.08] overflow-hidden">
 77→              <button onClick={() => setExpandedCheckId(isExpanded ? null : check.id)} className="w-full p-5 flex items-center gap-4 text-left hover:bg-white/[0.02] transition-colors">
 78→                <span className="text-lg">{meta.icon}</span>
 79→                <div className="flex-1 min-w-0">
 80→                  <p className="text-sm text-white font-medium truncate">&quot;{check.promptSent}&quot;</p>
 81→                  <div className="flex items-center gap-3 mt-1">
 82→                    <span className="text-xs text-gray-500">{meta.name}</span>
 83→                    <span className="text-xs text-gray-600">{new Date(check.createdAt).toLocaleDateString()}</span>
 84→                    <span className="text-xs text-gray-600">{check.responseTimeMs}ms</span>
 85→                  </div>
 86→                </div>
 87→                <div className="flex items-center gap-3 shrink-0">
 88→                  <span className={`text-xs font-medium px-2 py-1 rounded-full ${isCited ? 'bg-green-500/20 text-green-400' : 'bg-gray-500/20 text-gray-400'}`}>
 89→                    {isCited ? 'Cité' : 'Non cité'}
 90→                  </span>
 91→                  <span className={`text-xs font-bold px-2 py-1 rounded-full ${getScoreBadge(check.detection.citationScore)}`}>
 92→                    {check.detection.citationScore}
 93→                  </span>
 94→                  {isExpanded ? <ChevronUp size={16} className="text-gray-500" /> : <ChevronDown size={16} className="text-gray-500" />}
 95→                </div>
 96→              </button>
 97→
 98→              {isExpanded && (
 99→                <div className="px-5 pb-5 border-t border-white/[0.06] pt-4 animate-in slide-in-from-top-1">
100→                  {/* Detection details */}
101→                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mb-4">
102→                    <div className="bg-white/[0.03] p-3 rounded-xl">
103→                      <p className="text-[10px] text-gray-600 uppercase">URL Match</p>
104→                      <p className="text-sm font-medium text-white">{check.detection.urlExactMatch ? '✅ Exact' : check.detection.urlPartialMatch ? '🔶 Partiel' : '❌ Non'}</p>
105→                    </div>
106→                    <div className="bg-white/[0.03] p-3 rounded-xl">
107→                      <p className="text-[10px] text-gray-600 uppercase">Marque</p>
108→                      <p className="text-sm font-medium text-white">{check.detection.brandExactMatch ? '✅ Détectée' : '❌ Non'}</p>
109→                    </div>
110→                    <div className="bg-white/[0.03] p-3 rounded-xl">
111→                      <p className="text-[10px] text-gray-600 uppercase">Position</p>
112→                      <p className="text-sm font-medium text-white">
113→                        {check.detection.positionInResponse === 'first_paragraph' ? '🥇 Premier §' :
114→                         check.detection.positionInResponse === 'middle' ? '📍 Milieu' :
115→                         check.detection.positionInResponse === 'end' ? '📍 Fin' : '📎 Footnote'}
116→                      </p>
117→                    </div>
118→                    <div className="bg-white/[0.03] p-3 rounded-xl">
119→                      <p className="text-[10px] text-gray-600 uppercase">Sentiment</p>
120→                      <p className="text-sm font-medium text-white">
121→                        {check.detection.sentiment === 'positive' ? '👍 Positif' :
122→                         check.detection.sentiment === 'negative' ? '👎 Négatif' : '🔘 Neutre'}
123→                      </p>
124→                    </div>
125→                  </div>
126→
127→                  {/* Response text */}
128→                  <div className="bg-white/[0.02] p-4 rounded-xl border border-white/[0.06]">
129→                    <p className="text-[10px] text-gray-600 uppercase mb-2">Réponse du moteur</p>
130→                    <p className="text-xs text-gray-400 whitespace-pre-wrap max-h-[200px] overflow-y-auto custom-scrollbar">
131→                      {check.responseText}
132→                    </p>
133→                  </div>
134→
135→                  {/* Sources */}
136→                  {check.responseSources.length > 0 && (
137→                    <div className="mt-3">
138→                      <p className="text-[10px] text-gray-600 uppercase mb-1.5">Sources citées</p>
139→                      <div className="flex flex-wrap gap-2">
140→                        {check.responseSources.map((src, i) => (
141→                          <span key={i} className="text-[10px] px-2 py-1 bg-white/[0.04] border border-white/[0.06] rounded text-gray-500 flex items-center gap-1">
142→                            <ExternalLink size={10} /> {src}
143→                          </span>
144→                        ))}
145→                      </div>
146→                    </div>
147→                  )}
148→
149→                  {/* Competitors before */}
150→                  {check.detection.competitorsBeforeUs.length > 0 && (
151→                    <div className="mt-3">
152→                      <p className="text-[10px] text-red-400 uppercase mb-1.5">Concurrents cités avant vous</p>
153→                      <div className="flex flex-wrap gap-2">
